.darma-loader-darma-custom-033 {
  height: 20px;
  width: 80px;
  transform: rotate(-30deg);
  background:
    radial-gradient(farthest-side, var(--loader-color, #f03355) 90%, #0000) left bottom/15px 15px no-repeat
    #ddd;
  animation:
    darma-loader-darma-custom-033-l17-0 2s infinite alternate linear,
    darma-loader-darma-custom-033-l17-1 2s infinite cubic-bezier(.75, 0, 1, .6);
}
@keyframes darma-loader-darma-custom-033-l17-0 {
  50% { transform: rotate(30deg); }
}
@keyframes darma-loader-darma-custom-033-l17-1 {
  50% { background-position: right bottom; }
}

